import { useState, useMemo, useRef, useEffect } from 'react';
export interface TreeNode { id: string; label: string; children?: ReadonlyArray<TreeNode>; }
export function Tree({ nodes, selectedId, onSelect }: { nodes: ReadonlyArray<TreeNode>; selectedId: string | null; onSelect: (id: string) => void }) {
  const [expanded, setExpanded] = useState<Set<string>>(new Set());
  const flat = useMemo(() => { const out: { node: TreeNode; depth: number; parentId: string | null }[] = []; const walk = (ns: ReadonlyArray<TreeNode>, d: number, p: string | null) => { for (const n of ns) { out.push({ node: n, depth: d, parentId: p }); if (expanded.has(n.id) && n.children) walk(n.children, d + 1, n.id); } }; walk(nodes, 0, null); return out; }, [nodes, expanded]);
  const typeBuffer = useRef('');
  const typeBufferTimer = useRef<number | null>(null);
  const onKey = (e: React.KeyboardEvent) => {
    const idx = flat.findIndex(f => f.node.id === selectedId);
    if (e.key === 'ArrowDown') { e.preventDefault(); const next = flat[Math.min(flat.length - 1, idx + 1)]; if (next) onSelect(next.node.id); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); const next = flat[Math.max(0, idx - 1)]; if (next) onSelect(next.node.id); }
    else if (e.key === 'ArrowRight') { e.preventDefault(); const cur = flat[idx]; if (cur?.node.children && !expanded.has(cur.node.id)) setExpanded(s => new Set([...s, cur.node.id])); else { const next = flat[idx + 1]; if (next) onSelect(next.node.id); } }
    else if (e.key === 'ArrowLeft') { e.preventDefault(); const cur = flat[idx]; if (cur && expanded.has(cur.node.id)) setExpanded(s => { const n = new Set(s); n.delete(cur.node.id); return n; }); else if (cur?.parentId) onSelect(cur.parentId); }
    else if (e.key.length === 1) { typeBuffer.current += e.key.toLowerCase(); if (typeBufferTimer.current) window.clearTimeout(typeBufferTimer.current); typeBufferTimer.current = window.setTimeout(() => { typeBuffer.current = ''; }, 600); const match = flat.find(f => f.node.label.toLowerCase().startsWith(typeBuffer.current)); if (match) onSelect(match.node.id); }
  };
  return (
    <div role="tree" tabIndex={0} onKeyDown={onKey} className="outline-none font-mono text-[12px]">
      {flat.map(f => (
        <div key={f.node.id} role="treeitem" aria-selected={f.node.id === selectedId} aria-expanded={f.node.children ? expanded.has(f.node.id) : undefined} onClick={() => onSelect(f.node.id)} className={`flex items-center h-6 cursor-pointer ${f.node.id === selectedId ? 'bg-[oklch(0.94_0.04_250)]' : ''}`} style={{ paddingLeft: 8 + f.depth * 16 }}>
          {f.node.children ? <span className="text-[oklch(0.55_0.005_250)] mr-1">{expanded.has(f.node.id) ? '\u25BE' : '\u25B8'}</span> : <span className="w-3 mr-1" />}
          {f.node.label}
        </div>
      ))}
    </div>
  );
}

