import { useState } from 'react';
export interface PollOption { id: string; label: string; }
export function LivePoll({ question, options, results, revealed, votedId, onVote }: { question: string; options: ReadonlyArray<PollOption>; results: ReadonlyArray<{ optionId: string; count: number }>; revealed: boolean; votedId: string | null; onVote: (id: string) => void }) {
  const totalVotes = results.reduce((s, r) => s + r.count, 0);
  return (
    <div className="max-w-2xl mx-auto py-12">
      <h2 className="text-[24px] mb-6 font-medium">{question}</h2>
      <div className="space-y-3">
        {options.map(opt => {
          const count = results.find(r => r.optionId === opt.id)?.count ?? 0;
          const pct = totalVotes > 0 ? (count / totalVotes) * 100 : 0;
          const isVoted = votedId === opt.id;
          return (
            <button key={opt.id} type="button" onClick={() => onVote(opt.id)} disabled={!!votedId} className={`relative w-full text-left px-4 py-3 border-2 rounded-md ${isVoted ? 'border-[oklch(0.55_0.18_250)]' : 'border-[oklch(0.92_0.005_250)] hover:border-[oklch(0.85_0.005_250)]'} disabled:cursor-default disabled:hover:border-[oklch(0.92_0.005_250)]`}>
              {revealed && <div className="absolute inset-y-0 left-0 bg-[oklch(0.94_0.04_250)] rounded-l-md" style={{ width: `${pct}%`, transition: 'width 600ms ease-out' }} />}
              <div className="relative flex justify-between items-center">
                <span className="text-[16px]">{opt.label}</span>
                {revealed && <span className="text-[14px] tabular-nums font-medium">{pct.toFixed(0)}%</span>}
              </div>
            </button>
          );
        })}
      </div>
      {votedId && !revealed && <p className="mt-4 text-[12px] text-[oklch(0.55_0.005_250)] text-center">Your vote is in. Results show when voting closes.</p>}
    </div>
