import { useState, useEffect } from 'react';
export function Pagination({ currentPage, totalPages, onChange }: { currentPage: number; totalPages: number; onChange: (page: number) => void }) {
  const [input, setInput] = useState(String(currentPage));
  useEffect(() => setInput(String(currentPage)), [currentPage]);
  const commit = () => { const n = parseInt(input, 10); if (!isNaN(n) && n >= 1 && n <= totalPages) onChange(n); else setInput(String(currentPage)); };
  return (
    <nav aria-label="Pagination" className="flex items-center gap-2 text-[13px]">
      <button type="button" onClick={() => onChange(1)} disabled={currentPage === 1} className="px-2 py-1 disabled:opacity-30">First</button>
      <button type="button" onClick={() => onChange(Math.max(1, currentPage - 1))} disabled={currentPage === 1} className="px-2 py-1 disabled:opacity-30">\u2039 Prev</button>
      <span className="text-[oklch(0.55_0.005_250)]">Page</span>
      <input value={input} onChange={(e) => setInput(e.target.value)} onBlur={commit} onKeyDown={(e) => { if (e.key === 'Enter') commit(); }} inputMode="numeric" aria-label="Page number" className="w-12 h-8 text-center font-mono tabular-nums border border-[oklch(0.85_0.005_250)] rounded outline-none focus:border-[oklch(0.55_0.18_250)]" />
      <span className="text-[oklch(0.55_0.005_250)]">of {totalPages}</span>
      <button type="button" onClick={() => onChange(Math.min(totalPages, currentPage + 1))} disabled={currentPage === totalPages} className="px-2 py-1 disabled:opacity-30">Next \u203A</button>
      <button type="button" onClick={() => onChange(totalPages)} disabled={currentPage === totalPages} className="px-2 py-1 disabled:opacity-30">Last</button>
    </nav>
  );
}

