export interface CalEvent { id: string; title: string; startMin: number; endMin: number; date: string; color: string; }
function layoutOverlapping(events: ReadonlyArray<CalEvent>): Array<CalEvent & { col: number; cols: number }> {
  // Greedy: assign to leftmost free column.
  const sorted = [...events].sort((a, b) => a.startMin - b.startMin);
  const columns: CalEvent[][] = [];
  const placed: Array<CalEvent & { col: number; cols: number }> = [];
  for (const ev of sorted) {
    let col = 0;
    while (columns[col] && columns[col].some(e => e.endMin > ev.startMin && e.startMin < ev.endMin)) col++;
    if (!columns[col]) columns[col] = [];
    columns[col].push(ev);
    placed.push({ ...ev, col, cols: 0 });
  }
  // Recompute cols (max overlap depth)
  for (const p of placed) p.cols = columns.length;
  return placed;
}
export function WeekView({ events, days }: { events: ReadonlyArray<CalEvent>; days: ReadonlyArray<string> }) {
  const HOUR_H = 60;
  return (
    <div className="flex border border-[oklch(0.92_0.005_250)]">
      <div className="w-12 text-[10px] text-[oklch(0.55_0.005_250)] tabular-nums">{Array.from({ length: 24 }).map((_, h) => <div key={h} className="h-15 pt-1 pl-1" style={{ height: HOUR_H }}>{String(h).padStart(2, '0')}:00</div>)}</div>
      {days.map(day => { const dayEvents = layoutOverlapping(events.filter(e => e.date === day)); return (
        <div key={day} className="flex-1 relative border-l border-[oklch(0.95_0.005_250)]" style={{ height: 24 * HOUR_H }}>
          {Array.from({ length: 24 }).map((_, h) => <div key={h} className="border-b border-[oklch(0.97_0.005_250)]" style={{ height: HOUR_H }} />)}
          {dayEvents.map(ev => { const top = ev.startMin / 60 * HOUR_H; const height = (ev.endMin - ev.startMin) / 60 * HOUR_H; const width = `${100 / Math.max(1, ev.cols)}%`; const left = `${(ev.col / Math.max(1, ev.cols)) * 100}%`; return (
            <div key={ev.id} className="absolute rounded text-[12px] font-medium text-white p-1 truncate" style={{ background: ev.color, opacity: 0.85, top, height, width, left }}>{ev.title}</div>
          ); })}
        </div>
      ); })}
    </div>
  );
}

