// ConditionalField.tsx
import { useEffect, useRef, useState } from 'react';
export function ConditionalField({ visible, children }: { visible: boolean; children: React.ReactNode }) {
  const ref = useRef<HTMLDivElement | null>(null);
  const [height, setHeight] = useState<string>(visible ? 'auto' : '0px');
  useEffect(() => {
    const el = ref.current; if (!el) return;
    if (visible) { setHeight(`${el.scrollHeight}px`); const t = window.setTimeout(() => setHeight('auto'), 200); return () => window.clearTimeout(t); }
    else { setHeight(`${el.scrollHeight}px`); requestAnimationFrame(() => setHeight('0px')); }
  }, [visible]);
  return (
    <div ref={ref} aria-hidden={!visible} style={{ height, overflow: 'hidden', opacity: visible ? 1 : 0, transition: 'height 200ms cubic-bezier(0.22, 1, 0.36, 1), opacity 200ms ease-out' }}>
      {children}
    </div>
  );
}

