// DelayedSkeleton.tsx
import { useEffect, useRef, useState } from 'react';
export function DelayedSkeleton({ loading, skeleton, children, delayMs = 200, minDurationMs = 400 }: { loading: boolean; skeleton: React.ReactNode; children: React.ReactNode; delayMs?: number; minDurationMs?: number }) {
  const [show, setShow] = useState(false);
  const showedAt = useRef<number | null>(null);
  useEffect(() => {
    if (loading) { const t = window.setTimeout(() => { setShow(true); showedAt.current = Date.now(); }, delayMs); return () => window.clearTimeout(t); }
    else { if (show && showedAt.current) { const elapsed = Date.now() - showedAt.current; const remaining = Math.max(0, minDurationMs - elapsed); const t = window.setTimeout(() => setShow(false), remaining); return () => window.clearTimeout(t); } else { setShow(false); } }
  }, [loading, show, delayMs, minDurationMs]);
  if (loading || show) return <>{skeleton}</>;
  return <>{children}</>;
}

