export interface LineItem { id: string; description: string; quantity: number; priceCents: number; }
export function Invoice({ lineItems, discountCents = 0, taxRate = 0 }: { lineItems: ReadonlyArray<LineItem>; discountCents?: number; taxRate?: number }) {
  const subtotal = lineItems.reduce((s, i) => s + i.quantity * i.priceCents, 0);
  const afterDiscount = subtotal - discountCents;
  const tax = Math.round(afterDiscount * taxRate);
