  return (
    <div className="max-w-2xl mx-auto bg-white p-8">
      <table className="w-full text-[13px]">
        <thead><tr className="border-b border-[oklch(0.92_0.005_250)]"><th className="text-left py-2 text-[11px] uppercase text-[oklch(0.55_0.005_250)]">Description</th><th className="text-right text-[11px] uppercase text-[oklch(0.55_0.005_250)] w-20">Qty</th><th className="text-right text-[11px] uppercase text-[oklch(0.55_0.005_250)] w-24">Price</th><th className="text-right text-[11px] uppercase text-[oklch(0.55_0.005_250)] w-28">Total</th></tr></thead>
        <tbody>{lineItems.map(i => (
          <tr key={i.id} className="border-b border-[oklch(0.95_0.005_250)]"><td className="py-2">{i.description}</td><td className="text-right tabular-nums">{i.quantity}</td><td className="text-right tabular-nums">{fmt(i.priceCents)}</td><td className="text-right tabular-nums">{fmt(i.quantity * i.priceCents)}</td></tr>
        ))}</tbody>
      </table>
      <div className="mt-4 flex flex-col items-end gap-1 text-[13px] tabular-nums">
        <div className="flex gap-8"><span className="text-[oklch(0.55_0.005_250)]">Subtotal</span><span className="w-24 text-right">{fmt(subtotal)}</span></div>
        {discountCents > 0 && <div className="flex gap-8"><span className="text-[oklch(0.55_0.005_250)]">Discount</span><span className="w-24 text-right text-[oklch(0.55_0.14_145)]">-{fmt(discountCents)}</span></div>}
        {taxRate > 0 && <div className="flex gap-8"><span className="text-[oklch(0.55_0.005_250)]">Tax ({(taxRate * 100).toFixed(1)}%)</span><span className="w-24 text-right">{fmt(tax)}</span></div>}
        <div className="flex gap-8 mt-2 pt-2 border-t border-[oklch(0.92_0.005_250)]"><span className="font-medium text-[oklch(0.18_0.005_250)]">Total</span><span className="w-24 text-right font-medium text-[18px]">{fmt(total)}</span></div>
      </div>
    </div>
  );
}

// EditableCell.tsx
import { useState, useRef, useEffect } from 'react';
export function EditableCell({ value, onCommit, onMove }: { value: string; onCommit: (v: string) => void; onMove?: (dir: 'up' | 'down' | 'left' | 'right') => void }) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value);
  const inputRef = useRef<HTMLInputElement | null>(null);
  useEffect(() => { if (editing) inputRef.current?.focus(); }, [editing]);
  useEffect(() => setDraft(value), [value]);
  const enterEdit = () => { setDraft(value); setEditing(true); };
  const onKey = (e: React.KeyboardEvent) => {
    if (!editing && ((e.metaKey || e.ctrlKey) && e.key === 'e' || e.key === 'F2' || e.key === 'Enter')) { e.preventDefault(); enterEdit(); }
    else if (editing) {
      if (e.key === 'Escape') { setEditing(false); }
      else if (e.key === 'Enter') { onCommit(draft); setEditing(false); onMove?.('down'); }
      else if (e.key === 'Tab') { e.preventDefault(); onCommit(draft); setEditing(false); onMove?.(e.shiftKey ? 'left' : 'right'); }
    }
  };
  return (
    <div onKeyDown={onKey} tabIndex={0} onDoubleClick={enterEdit} className="relative h-8 px-2 outline-none" style={{ border: editing ? '2px solid oklch(0.55 0.18 250)' : '1px solid transparent', margin: editing ? '-1px' : '0' }}>
      {editing ? <input ref={inputRef} value={draft} onChange={(e) => setDraft(e.target.value)} className="w-full h-full bg-transparent outline-none" /> : <span>{value}</span>}
    </div>
  );
}

