// OTPInput.tsx
import { useRef } from 'react';
export function OTPInput({ length = 6, onComplete }: { length?: number; onComplete: (code: string) => void }) {
  const refs = useRef<HTMLInputElement[]>([]);
  const onChange = (i: number, val: string) => {
    if (val.length > 1) { // paste
      const digits = val.replace(/\D/g, '').slice(0, length);
      digits.split('').forEach((d, j) => { if (refs.current[j]) refs.current[j].value = d; });
      const lastIdx = Math.min(digits.length, length - 1);
      refs.current[lastIdx]?.focus();
      if (digits.length === length) onComplete(digits);
    } else if (val.length === 1) {
      if (i < length - 1) refs.current[i + 1]?.focus();
      const code = refs.current.map(r => r?.value ?? '').join('');
      if (code.length === length) onComplete(code);
    }
  };
  const onKey = (i: number, e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Backspace' && (e.currentTarget.value === '' && i > 0)) { refs.current[i - 1]?.focus(); }
  };
  return (
    <div className="flex gap-1">{Array.from({ length }).map((_, i) => <input key={i} ref={(el) => { if (el) refs.current[i] = el; }} maxLength={1} inputMode="numeric" autoComplete={i === 0 ? 'one-time-code' : undefined} onChange={(e) => onChange(i, e.target.value)} onKeyDown={(e) => onKey(i, e)} className="w-10 h-12 text-center text-[24px] font-mono tabular-nums border border-[oklch(0.85_0.005_250)] rounded outline-none focus:border-[oklch(0.55_0.18_250)]" aria-label={`Digit ${i + 1}`} />)}</div>
  );
}

