import { createContext, useContext, useEffect, useState } from 'react';
export type ThemeMode = 'system' | 'light' | 'dark';
interface Ctx { mode: ThemeMode; setMode: (m: ThemeMode) => void; resolvedTheme: 'light' | 'dark'; }
const C = createContext<Ctx | null>(null);
export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [mode, setModeState] = useState<ThemeMode>(() => (typeof localStorage !== 'undefined' ? (localStorage.getItem('theme-mode') as ThemeMode) ?? 'system' : 'system'));
  const [systemDark, setSystemDark] = useState(() => typeof window !== 'undefined' && matchMedia('(prefers-color-scheme: dark)').matches);
  useEffect(() => { const mq = matchMedia('(prefers-color-scheme: dark)'); const on = () => setSystemDark(mq.matches); mq.addEventListener('change', on); return () => mq.removeEventListener('change', on); }, []);
  const resolvedTheme: 'light' | 'dark' = mode === 'system' ? (systemDark ? 'dark' : 'light') : mode;
  useEffect(() => { document.documentElement.dataset.theme = resolvedTheme; }, [resolvedTheme]);
  const setMode = (m: ThemeMode) => { setModeState(m); try { localStorage.setItem('theme-mode', m); } catch {} };
  return <C.Provider value={{ mode, setMode, resolvedTheme }}>{children}</C.Provider>;
}
export const useTheme = () => { const v = useContext(C); if (!v) throw new Error('ThemeProvider missing'); return v; };
// ThemeToggle.tsx
