// useMutationQueue.ts (sketch)
import { useEffect, useState } from 'react';
interface Mutation { id: string; payload: unknown; }
export function useMutationQueue(executeFn: (m: Mutation) => Promise<void>) {
  const [queue, setQueue] = useState<Mutation[]>([]);
  const [online, setOnline] = useState(typeof navigator !== 'undefined' ? navigator.onLine : true);
  useEffect(() => {
    const on = () => setOnline(true); const off = () => setOnline(false);
    window.addEventListener('online', on); window.addEventListener('offline', off);
    return () => { window.removeEventListener('online', on); window.removeEventListener('offline', off); };
  }, []);
  useEffect(() => {
    if (!online || queue.length === 0) return;
    (async () => { const next = queue[0]; try { await executeFn(next); setQueue(q => q.slice(1)); } catch { /* retry next cycle */ } })();
  }, [online, queue, executeFn]);
  const enqueue = (m: Mutation) => setQueue(q => [...q, m]);
  return { enqueue, queueLength: queue.length, online };
}
export function SyncIndicator({ queueLength, online }: { queueLength: number; online: boolean }) {
  if (queueLength === 0 && online) return null;
  return (
    <div role="status" aria-live="polite" className="fixed bottom-4 left-4 px-3 py-1.5 bg-[oklch(0.7_0.16_60)] text-white text-[11px] rounded-full">
      {!online && '\u2295 Offline \u00B7 '}{queueLength > 0 && `${queueLength} pending`}
    </div>
  );
}

