import { useState } from 'react';
export function RichCommandPalette<T extends { id: string; label: string }>({ items, renderPreview, onSelect, open, onClose }: { items: ReadonlyArray<T>; renderPreview: (item: T) => React.ReactNode; onSelect: (item: T) => void; open: boolean; onClose: () => void }) {
  const [query, setQuery] = useState('');
