  const filtered = items.filter(i => i.label.toLowerCase().includes(query.toLowerCase()));
  if (!open) return null;
  return (
    <div role="dialog" aria-label="Command palette" className="fixed inset-0 z-50 flex items-start justify-center pt-[12vh] bg-black/40" onClick={onClose}>
