        <input autoFocus value={query} onChange={(e) => { setQuery(e.target.value); setFocusIdx(0); }} onKeyDown={(e) => {
          if (e.key === 'ArrowDown') { e.preventDefault(); setFocusIdx(i => Math.min(filtered.length - 1, i + 1)); }
          else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - 1)); }
          else if (e.key === 'Enter') { e.preventDefault(); if (filtered[focusIdx]) { onSelect(filtered[focusIdx]); onClose(); } }
