            {filtered.map((item, i) => <li key={item.id} role="option" aria-selected={i === focusIdx} onMouseEnter={() => setFocusIdx(i)} onClick={() => { onSelect(item); onClose(); }} className={`px-3 py-2 text-[13px] cursor-pointer ${i === focusIdx ? 'bg-[oklch(0.94_0.04_250)]' : ''}`}>{item.label}</li>)}
