import { useState } from 'react';
export interface RadarSeries { id: string; label: string; color: string; values: ReadonlyArray<number>; }
export function RadarChart({ axes, series, max = 100 }: { axes: ReadonlyArray<string>; series: ReadonlyArray<RadarSeries>; max?: number }) {
  const [hoverId, setHoverId] = useState<string | null>(null);
  const CX = 160, CY = 160, R = 120;
  const angle = (i: number) => -Math.PI / 2 + (i / axes.length) * Math.PI * 2;
  const point = (val: number, i: number) => `${(CX + Math.cos(angle(i)) * (val / max) * R).toFixed(1)},${(CY + Math.sin(angle(i)) * (val / max) * R).toFixed(1)}`;
  return (
    <div>
      <svg width={320} height={320}>
        {[0.25, 0.5, 0.75, 1].map(p => <polygon key={p} points={axes.map((_, i) => point(max * p, i)).join(' ')} fill="none" stroke="oklch(0.92 0.005 250)" strokeWidth="1" />)}
        {axes.map((label, i) => { const x = CX + Math.cos(angle(i)) * (R + 16); const y = CY + Math.sin(angle(i)) * (R + 16); return <text key={label} x={x} y={y} fontSize="11" textAnchor="middle" dominantBaseline="middle" fill="oklch(0.55 0.005 250)">{label}</text>; })}
        {series.map(s => { const dim = hoverId && hoverId !== s.id; return <polygon key={s.id} points={s.values.map((v, i) => point(v, i)).join(' ')} fill={s.color} fillOpacity={dim ? 0.05 : 0.3} stroke={s.color} strokeWidth="2" style={{ opacity: dim ? 0.3 : 1, transition: 'opacity 150ms ease-out' }} />; })}
      </svg>
